// src/pages/Login.js
import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";
import { useNavigate, Link } from "react-router-dom";

export default function Login() {
  const { login, googleLogin, resetPassword } = useAuth();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");
  const navigate = useNavigate();

  const onSubmit = async (e) => {
    e.preventDefault();
    setErr("");
    setLoading(true);
    try {
      await login(email, password);
      navigate("/dashboard");
    } catch (error) {
      setErr(error.message || "Login failed");
    } finally {
      setLoading(false);
    }
  };

  const handleGoogle = async () => {
    try {
      await googleLogin();
      navigate("/dashboard");
    } catch (err) {
      setErr(err.message || "Google login failed");
    }
  };

  const handleReset = async () => {
    if (!email) return setErr("Enter your email to reset password.");
    try {
      await resetPassword(email);
      setErr("Password reset email sent.");
    } catch (e) {
      setErr(e.message || "Could not send reset email.");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4">
      <div className="w-full max-w-md bg-white dark:bg-gray-900 rounded-xl p-6 shadow-lg">
        <h2 className="text-2xl font-bold mb-3 text-primary dark:text-white">Login</h2>
        {err && <div className="mb-3 text-sm text-red-500">{err}</div>}
        <form onSubmit={onSubmit} className="space-y-3">
          <input
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            type="email"
            placeholder="Email"
            className="w-full px-3 py-2 border rounded"
            required
          />
          <div className="relative">
            <input
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              type={showPw ? "text" : "password"}
              placeholder="Password"
              className="w-full px-3 py-2 border rounded"
              required
            />
            <button
              type="button"
              onClick={() => setShowPw(s => !s)}
              className="absolute right-2 top-2 text-sm"
            >
              {showPw ? "Hide" : "Show"}
            </button>
          </div>

          <div className="flex items-center justify-between text-sm">
            <button type="button" onClick={handleReset} className="text-blue-600">Forgot password?</button>
            <Link to="/signup" className="text-yellow-600">Create an account</Link>
          </div>

          <button disabled={loading} type="submit" className="w-full bg-yellow-400 text-black py-2 rounded">
            {loading ? "Signing in..." : "Login"}
          </button>
        </form>

        <div className="my-4 flex items-center">
          <hr className="flex-grow" />
          <span className="px-2 text-sm text-gray-500">OR</span>
          <hr className="flex-grow" />
        </div>

        <button onClick={handleGoogle} className="w-full border py-2 rounded flex items-center justify-center space-x-2">
          <img src="https://upload.wikimedia.org/wikipedia/commons/5/53/Google_%22G%22_Logo.svg" alt="G" className="w-5 h-5" />
          <span>Sign in with Google</span>
        </button>
      </div>
    </div>
  );
}
